public class LmdbIdBGPAccessPathTest {

	private static final String NS = "http://example.com/access-path/";

	@Test
	public void collectsMembershipIdsAfterColdFilter(@TempDir java.nio.file.Path tempDir) throws IOException {
		LmdbStore store = LmdbTestUtil.newStoreWithLmdbEvaluationStrategy(tempDir.toFile());
		store.setDefaultIsolationLevel(IsolationLevels.READ_COMMITTED);
		SailRepository repository = new SailRepository(store);
		repository.init();

		ValueFactory vf = SimpleValueFactory.getInstance();
		IRI hasObservation = vf.createIRI(NS, "hasObservation");
		IRI observationValue = vf.createIRI(NS, "observationValue");
		IRI encLow = vf.createIRI(NS, "encLow");
		IRI encHigh = vf.createIRI(NS, "encHigh");
		IRI obsLow = vf.createIRI(NS, "obsLow");
		IRI obsHigh = vf.createIRI(NS, "obsHigh");

		try (RepositoryConnection conn = repository.getConnection()) {
			conn.add(encLow, hasObservation, obsLow);
			conn.add(obsLow, observationValue, vf.createLiteral(42));
			conn.add(encHigh, hasObservation, obsHigh);
			conn.add(obsHigh, observationValue, vf.createLiteral(75));
		}

		StatementPattern observationPattern = new StatementPattern(new Var("enc"),
				new Var("hasObservation", hasObservation), new Var("obs"));
		StatementPattern valuePattern = new StatementPattern(new Var("obs"),
				new Var("observationValue", observationValue), new Var("value"));
		Filter filteredValuePattern = new Filter(valuePattern,
				new Compare(new Var("value"), new ValueConstant(vf.createLiteral(60)), Compare.CompareOp.LT));
		Join rightBranch = new Join(observationPattern, filteredValuePattern);
		List<StatementPattern> patterns = new ArrayList<>();
		assertThat(LmdbIdBGPQueryEvaluationStep.flattenBGP(rightBranch, patterns)).isTrue();

		SailSource branch = store.getBackingStore().getExplicitSailSource();
		SailDataset dataset = branch.dataset(IsolationLevels.READ_COMMITTED);
		try {
			LmdbEvaluationDataset lmdbDataset = (LmdbEvaluationDataset) dataset;
			LmdbSailDatasetTripleSource tripleSource = new LmdbSailDatasetTripleSource(repository.getValueFactory(),
					dataset);
			QueryEvaluationContext ctx = new LmdbQueryEvaluationContext(null, tripleSource.getValueFactory(),
					tripleSource.getComparator(), lmdbDataset, lmdbDataset.getValueStore());
			LmdbEvaluationStrategy strategy = new LmdbEvaluationStrategy(tripleSource, null, null, 0,
					new EvaluationStatistics(), false);
			LmdbIdBGPQueryEvaluationStep step = new LmdbIdBGPQueryEvaluationStep(strategy, rightBranch, patterns, ctx,
					null);

			IdMembership membership = step.collectExistingIds(EmptyBindingSet.getInstance(), "enc");

			long encLowId = lmdbDataset.getValueStore().getId(encLow);
			long encHighId = lmdbDataset.getValueStore().getId(encHigh);
			assertThat(membership).as("cold-filtered RHS should still be collectible as an ID membership set")
					.isNotNull();
			assertThat(membership.contains(encLowId)).isTrue();
			assertThat(membership.contains(encHighId)).isFalse();
			assertThat(membership.rowsScanned()).isGreaterThan(0);
		} finally {
			dataset.close();
			branch.close();
			repository.shutDown();
		}
	}
}
